from instructor import from_openai

from pydantic import BaseModel, Field
from vex import verify

class DeIdentifiedPatient(BaseModel):
    age_range: str = Field(..., json_schema_extra={'examples': ['20-30', '30-40']})
    chief_complaint: str
    medications: list[str]

client = from_openai(openai_client)
@verify()
def extract_patient_summary(text: str) -> DeIdentifiedPatient:
    return client.chat.completions.create(
        model='gpt-4o',
        response_model=DeIdentifiedPatient,
        messages=[{'role': 'user', 'content': f"Extract from: {text}"}]
    )

from instructor import from_openai
from pydantic import BaseModel, Field
from typing import List
from vex import verify

class MedicationRecord(BaseModel):
    ndc_code: str = Field(..., pattern=r'^\d{5}-\d{4}-\d{2}$')
    dosage_mg: float
    frequency: str = Field(..., json_schema_extra={'examples': ['QD', 'BID', 'TID']})

@verify(policy='block-on-fail')
def reconcile_medications(notes: str) -> List[MedicationRecord]:
    client = from_openai(openai_client)
    return client.chat.completions.create(
        model='gpt-4o',
        response_model=List[MedicationRecord],
        messages=[{'role': 'user', 'content': f"Extract medications: {notes}"}]
    )

import { fromOpenAI } from 'instructor';
import { z } from 'zod';
import { verify } from 'vex-sdk';

const TriageForm = z.object({
  acuity_level: z.enum(['LEVEL_1', 'LEVEL_2', 'LEVEL_3', 'LEVEL_4', 'LEVEL_5']),
  vital_signs: z.object({
    heart_rate: z.number().min(40).max(200),
    blood_pressure: z.object({
      systolic: z.number().min(70).max(220),
      diastolic: z.number().min(40).max(140)
    })
  })
});

const client = fromOpenAI(openaiClient);

verify({
  policy: 'retry-on-fail',
  maxRetries: 3
})(async (notes: string) => {
  return client.chat.completions.create({
    model: 'gpt-4o',
    responseModel: TriageForm,
    messages: [{ role: 'user', content: `Triage: ${notes}` }]
  });
});
